from collections import deque

class Solution:
    def minimumThreshold(self, n, edges, source, target, k):
        if source == target:
            return 0

        def heavy_needed(threshold):
            adj = [[] for _ in range(n)]
            for u, v, w in edges:
                cost = 0 if w <= threshold else 1
                adj[u].append((v, cost))
                adj[v].append((u, cost))
            INF = float('inf')
            dist = [INF] * n
            dist[source] = 0
            dq = deque([source])
            while dq:
                u = dq.popleft()
                for v, c in adj[u]:
                    nd = dist[u] + c
                    if nd < dist[v]:
                        dist[v] = nd
                        if c == 0:
                            dq.appendleft(v)
                        else:
                            dq.append(v)
            return dist[target]

        candidates = sorted(set([0] + [w for _, _, w in edges]))
        lo, hi = 0, len(candidates) - 1
        ans = -1
        while lo <= hi:
            mid = (lo + hi) // 2
            d = heavy_needed(candidates[mid])
            if d != float('inf') and d <= k:
                ans = candidates[mid]
                hi = mid - 1
            else:
                lo = mid + 1
        return ans

