var minimumThreshold = function(n, edges, source, target, k) {
    if (source === target) return 0;

    function heavyNeeded(threshold) {
        const adj = Array.from({ length: n }, () => []);
        for (const [u, v, w] of edges) {
            const cost = w <= threshold ? 0 : 1;
            adj[u].push([v, cost]);
            adj[v].push([u, cost]);
        }
        const INF = Infinity;
        const dist = new Array(n).fill(INF);
        dist[source] = 0;
        const dq = [source];
        let head = 0;
        while (head < dq.length) {
            const u = dq[head++];
            for (const [v, c] of adj[u]) {
                const nd = dist[u] + c;
                if (nd < dist[v]) {
                    dist[v] = nd;
                    if (c === 0) {
                        dq.splice(head, 0, v);
                    } else {
                        dq.push(v);
                    }
                }
            }
        }
        return dist[target];
    }

    const weightSet = new Set([0]);
    for (const [, , w] of edges) weightSet.add(w);
    const candidates = Array.from(weightSet).sort((a, b) => a - b);
    let lo = 0, hi = candidates.length - 1;
    let ans = -1;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        const d = heavyNeeded(candidates[mid]);
        if (d !== Infinity && d <= k) {
            ans = candidates[mid];
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
};
